#!/usr/bin/env node
/**
 * Pre-bundles the Convex browser client into a single IIFE that the
 * widget can inline directly. Output goes to app/widget.js/_bundle.ts
 * (a TS file so the route handler can `import` it at build time).
 *
 * Replaces the old esm.sh CDN dependency — the widget now ships
 * fully self-contained, no external runtime fetches.
 *
 * Run automatically before `next build`. Manual: npm run build:widget
 */

import esbuild from "esbuild";
import { writeFile, mkdir } from "node:fs/promises";
import { dirname } from "node:path";

const STUB = `
import { ConvexClient } from "convex/browser";
globalThis.__PRAXTALK_CONVEX__ = { ConvexClient };
`;

const OUT = "app/widget.js/_bundle.ts";

async function main() {
  const result = await esbuild.build({
    stdin: { contents: STUB, resolveDir: process.cwd(), loader: "ts" },
    bundle: true,
    minify: true,
    format: "iife",
    target: ["es2020"],
    platform: "browser",
    write: false,
    treeShaking: true,
    legalComments: "none",
  });
  const bundle = result.outputFiles[0].text;
  // Wrap in a TS module that exports the bundled JS as a string. The
  // route handler imports this at build time and inlines it into the
  // widget source. JSON.stringify handles all escaping safely.
  const ts = `// Auto-generated by scripts/build-widget-bundle.mjs — do not edit.\nexport const CONVEX_CLIENT_BUNDLE = ${JSON.stringify(bundle)};\n`;
  await mkdir(dirname(OUT), { recursive: true });
  await writeFile(OUT, ts);
  console.log(
    `✓ Bundled Convex browser client → ${OUT} (${(bundle.length / 1024).toFixed(1)} KB minified)`,
  );
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
